import{_ as e,o as t,c as a,a as r}from"./app.0a43b3c6.js";const i={},s=r('<h1 id="why-data-structures-matter" tabindex="-1"><a class="header-anchor" href="#why-data-structures-matter" aria-hidden="true">#</a> Why Data Structures Matter</h1><h2 id="data-structures" tabindex="-1"><a class="header-anchor" href="#data-structures" aria-hidden="true">#</a> Data Structures</h2><ul><li>Data structures refer to how data is organized.</li></ul><h2 id="the-array-the-foundational-data-structure" tabindex="-1"><a class="header-anchor" href="#the-array-the-foundational-data-structure" aria-hidden="true">#</a> The Array: The Foundational Data Structure</h2><ul><li>When we measure how \u201Cfast\u201D an operation takes, we do not refer to how fast the operation takes in terms of pure time, but instead in how many steps it takes.</li><li>Measuring the speed of an operation in terms of time is undependable, since the time will always change depending on the hardware it is run on.</li><li>Measuring the speed of an operation is also known as measuring its time complexity.</li></ul><h2 id="sets-how-a-single-rule-can-affect-efficiency" tabindex="-1"><a class="header-anchor" href="#sets-how-a-single-rule-can-affect-efficiency" aria-hidden="true">#</a> Sets: How a Single Rule Can Affect Efficiency</h2><ul><li>A set is a data structure that does not allow duplicate values to be contained within it.</li><li>The computer will first need to search the set to see whether the value we want to insert is already there.</li><li>The best-case scenario of set&#39;s inserting: <code>N + 1</code>; The worst-case scenario of set&#39;s inserting: <code>2N + 1</code></li><li>Insertions for arrays are more efficient than insertions for sets.</li></ul>',7),n=[s];function o(h,c){return t(),a("div",null,n)}const l=e(i,[["render",o],["__file","index.html.vue"]]);export{l as default};
